+      'js': ['javascript-developer', 'backend-dev'],
+      'md': ['technical-writer'],
+      'json': ['config-specialist'],
+      'py': ['python-developer'],
+      'css': ['frontend-developer'],
+      'html': ['frontend-developer'],
+      'tsx': ['frontend-developer'],
+      'yml': ['devops-engineer'],
+      'yaml': ['devops-engineer'],
+      'sql': ['database-expert'],
