+    if (count > 100 && !highCount) highCount = { state, count, q: actions['command-succeeded'] || 0 };
+    if (count < 5 && count > 0 && !lowCount) lowCount = { state, count, q: Object.values(actions).find(v => typeof v === 'number' && v !== count) || 0 };
